const $json = $input.first().json;
const html = $json.body;

// Issue 1: MathJax - collapsible content needs trigger
// Test 1: Check MathJax is included
const hasMathJax = html.includes('MathJax') && html.includes('tex-chtml.js');

// Test 2: Check toggleSection function triggers MathJax (CRITICAL for LaTeX to show)
const hasMathJaxTrigger = html.includes('MathJax.typesetPromise');

// Test 3: Check solution links exist
const hasSolutionLinks = html.includes('p1-ms/q') || html.includes('q18.html');

$json.mathjax = { included: hasMathJax, trigger: hasMathJaxTrigger };
$json.solutionLinks = hasSolutionLinks;

return $json;

const $json = $input.first().json;
const html = $json.body;

// Issue 2: Canvas not showing - needs initial render trigger
// Test: Check Canvas exists
const hasCanvas = html.includes('id="mathCanvas"');

// Test: Check ResizeObserver exists (for responsive canvas)
const hasResizeObserver = html.includes('ResizeObserver');

// Test: Check initial render is triggered (via setStep or direct call)
// CRITICAL: Without this, canvas stays blank on page load
const hasInitialRender = html.includes('setStep(') || html.includes('renderScene()');

// Test: Check for polyfill issues (can cause network errors)
const hasPolyfill = html.includes('polyfill.io');

$json.canvas = { 
  element: hasCanvas, 
  resizeObserver: hasResizeObserver, 
  initialRender: hasInitialRender,
  polyfill: hasPolyfill
};

return $json;
